const { fonte, temperatura, umidade } = msg.payload;
if (temperatura < -40 || temperatura > 80 || umidade < 0 || umidade > 100) {
    node.warn('Fora de faixa: ' + JSON.stringify(msg.payload));
    return null;
}
const temp = parseFloat(temperatura.toFixed(2));
const umi  = parseFloat(umidade.toFixed(2));
const hi   = calcHI(temp, umi);
const nivel = calcNivel(hi);
msg.topic   = 'INSERT INTO leituras (fonte, temperatura, umidade, heat_index, nivel_alerta, criado_em) VALUES (?, ?, ?, ?, ?, NOW())';
msg.payload = [fonte, temp, umi, hi, nivel];
msg._dados  = { fonte, temperatura: temp, umidade: umi, heat_index: hi, nivel };
return msg;
function calcHI(t,u){return parseFloat((-8.78469475556+1.61139411*t+2.33854883889*u-0.14611605*t*u-0.012308094*t*t-0.0164248277778*u*u+0.002211732*t*t*u+0.00072546*t*u*u-0.000003582*t*t*u*u).toFixed(2));}
function calcNivel(hi){if(hi>=54)return 'perigo_extremo';if(hi>=41)return 'perigo';if(hi>=32)return 'extrema_cautela';if(hi>=27)return 'cautela';return 'conforto';}

const { fonte, temperatura, umidade } = msg.payload;
if (temperatura < -40 || temperatura > 80 || umidade < 0 || umidade > 100) {
    node.warn('Fora de faixa: ' + JSON.stringify(msg.payload));
    return null;
}
const temp = parseFloat(temperatura.toFixed(2));
const umi  = parseFloat(umidade.toFixed(2));
const hi   = calcHI(temp, umi);
const nivel = calcNivel(hi);
msg.topic   = 'INSERT INTO leituras (fonte, temperatura, umidade, heat_index, nivel_alerta, criado_em) VALUES (?, ?, ?, ?, ?, NOW())';
msg.payload = [fonte, temp, umi, hi, nivel];
msg._dados  = { fonte, temperatura: temp, umidade: umi, heat_index: hi, nivel };
return msg;
function calcHI(t,u){return parseFloat((-8.78469475556+1.61139411*t+2.33854883889*u-0.14611605*t*u-0.012308094*t*t-0.0164248277778*u*u+0.002211732*t*t*u+0.00072546*t*u*u-0.000003582*t*t*u*u).toFixed(2));}
function calcNivel(hi){if(hi>=54)return 'perigo_extremo';if(hi>=41)return 'perigo';if(hi>=32)return 'extrema_cautela';if(hi>=27)return 'cautela';return 'conforto';}

const d = msg._dados;
if (!d) return [null, null, null];

const nivelLabel = {
    conforto:         'Conforto',
    cautela:          'Cautela',
    extrema_cautela:  'Cautela Extrema',
    perigo:           'Perigo',
    perigo_extremo:   'Perigo Extremo'
};

const nivelCor = {
    conforto:        '#3B6D11',
    cautela:         '#854F0B',
    extrema_cautela: '#854F0B',
    perigo:          '#A32D2D',
    perigo_extremo:  '#501313'
};

const nivelBg = {
    conforto:        '#EAF3DE',
    cautela:         '#FAEEDA',
    extrema_cautela: '#FAEEDA',
    perigo:          '#FCEBEB',
    perigo_extremo:  '#FCEBEB'
};

const nivelDot = {
    conforto:        '#639922',
    cautela:         '#BA7517',
    extrema_cautela: '#BA7517',
    perigo:          '#E24B4A',
    perigo_extremo:  '#A32D2D'
};

const payload = {
    temperatura: d.temperatura,
    umidade: d.umidade,
    heat_index: d.heat_index,
    nivel_label: nivelLabel[d.nivel] || d.nivel,
    nivel_cor: nivelCor[d.nivel] || '#333',
    nivel_bg: nivelBg[d.nivel] || '#eee',
    nivel_dot: nivelDot[d.nivel] || '#999',
    ts: new Date().toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' })
};

const msgChart = { payload: d.temperatura, topic: d.fonte };

let msgAlerta = null;
if (d.nivel !== 'conforto') {
    msgAlerta = { topic: 'alertas/conforto', payload: JSON.stringify({ nivel: d.nivel, fonte: d.fonte, heat_index: d.heat_index }), qos: 1 };
}

if (d.fonte === 'dht22') {
    return [{ payload }, null, msgChart, msgAlerta];
} else {
    return [null, { payload }, msgChart, msgAlerta];
}

msg.topic = 'SELECT fonte, temperatura, umidade, heat_index, nivel_alerta, criado_em FROM leituras WHERE criado_em >= NOW() - INTERVAL 24 HOUR ORDER BY criado_em ASC';
msg.payload = [];
return msg;

const rows = msg.payload;
if (!rows || rows.length === 0) return null;
node.send({ payload: [], action: 'replace' });
const msgs = rows.map(r => ({
    payload: r.temperatura,
    topic:   r.fonte,
    timestamp: new Date(r.criado_em).getTime()
}));
return [msgs];

const c = msg.payload.current;
if (!c) { node.error('Open-Meteo: resposta inesperada', msg); return null; }
const temp = parseFloat(c.temperature_2m.toFixed(2));
const umi  = parseFloat(c.relative_humidity_2m.toFixed(2));
const hi = parseFloat((-8.78469475556+1.61139411*temp+2.33854883889*umi-0.14611605*temp*umi-0.012308094*temp*temp-0.0164248277778*umi*umi+0.002211732*temp*temp*umi+0.00072546*temp*umi*umi-0.000003582*temp*temp*umi*umi).toFixed(2));
let nivel = 'conforto';
if (hi >= 54) nivel = 'perigo_extremo';
else if (hi >= 41) nivel = 'perigo';
else if (hi >= 32) nivel = 'extrema_cautela';
else if (hi >= 27) nivel = 'cautela';
msg.topic = 'INSERT INTO leituras (fonte, temperatura, umidade, heat_index, nivel_alerta, criado_em) VALUES (?, ?, ?, ?, ?, NOW())';
msg.payload = ['openmeteo', temp, umi, hi, nivel];
msg._dados = { fonte: 'openmeteo', temperatura: temp, umidade: umi, heat_index: hi, nivel };
return msg;

const d = msg._dados;
if (!d) return [null, null];
const nivelLabel = { conforto:'Conforto', cautela:'Cautela', extrema_cautela:'Cautela Extrema', perigo:'Perigo', perigo_extremo:'Perigo Extremo' };
const nivelCor   = { conforto:'#3B6D11', cautela:'#854F0B', extrema_cautela:'#854F0B', perigo:'#A32D2D', perigo_extremo:'#501313' };
const nivelBg    = { conforto:'#EAF3DE', cautela:'#FAEEDA', extrema_cautela:'#FAEEDA', perigo:'#FCEBEB', perigo_extremo:'#FCEBEB' };
const nivelDot   = { conforto:'#639922', cautela:'#BA7517', extrema_cautela:'#BA7517', perigo:'#E24B4A', perigo_extremo:'#A32D2D' };
return [
    { payload: {
        temperatura: d.temperatura, umidade: d.umidade, heat_index: d.heat_index,
        nivel_label: nivelLabel[d.nivel] || d.nivel,
        nivel_cor:   nivelCor[d.nivel]   || '#333',
        nivel_bg:    nivelBg[d.nivel]    || '#eee',
        nivel_dot:   nivelDot[d.nivel]   || '#999',
        ts: new Date().toLocaleTimeString('pt-BR', { hour:'2-digit', minute:'2-digit' })
    }},
    { payload: d.temperatura, topic: 'openmeteo' }
];

const limit = parseInt(msg.req.query.limit) || 50000;
const fonte = msg.req.query.fonte || null;
if (fonte) {
    msg.topic   = 'SELECT * FROM leituras WHERE fonte = ? ORDER BY criado_em DESC LIMIT ?';
    msg.payload = [fonte, limit];
} else {
    msg.topic   = 'SELECT * FROM leituras ORDER BY criado_em DESC LIMIT ?';
    msg.payload = [limit];
}
return msg;

msg.payload = msg.payload.map(r => ({
    ...r,
    criado_em: r.criado_em instanceof Date
        ? r.criado_em.toISOString().replace('T',' ').substring(0,19)
        : r.criado_em
}));
return msg;

const tipo  = msg.payload.tipo;
const horas = msg.payload.horas || 6;
msg._tipo   = tipo;
msg._horas  = horas;
msg.topic   = `SELECT fonte,
    ROUND(AVG(temperatura),2) AS temp_media,
    ROUND(MIN(temperatura),2) AS temp_min,
    ROUND(MAX(temperatura),2) AS temp_max,
    ROUND(AVG(umidade),2)     AS umid_media,
    ROUND(AVG(heat_index),2)  AS hi_medio,
    ROUND(MAX(heat_index),2)  AS hi_max,
    COUNT(*) AS total
FROM leituras
WHERE criado_em >= NOW() - INTERVAL ${horas} HOUR
GROUP BY fonte`;
msg.payload = [];
return msg;

const tipo  = msg._tipo;
const horas = msg._horas;
const resumo = msg.payload;

let ctx = `Dados do Monitor Climático — Catanduva, SP, Brasil\nÚltimas ${horas}h:\n`;
for (const r of resumo) {
    ctx += `Fonte ${r.fonte}: temp média ${r.temp_media}°C (min ${r.temp_min}, max ${r.temp_max}), umidade média ${r.umid_media}%, Heat Index médio ${r.hi_medio}°C, ${r.total} leituras\n`;
}

const sufixos = {
    rapida:   'Faça uma análise rápida das condições climáticas atuais. Seja direto. Máximo 4 linhas.',
    conforto: 'Analise conforto térmico interno (DHT22) vs externo (DHT11/Open-Meteo). Tempo fora da zona ASHRAE (20-26°C, 30-60% UR). Recomendações práticas.',
    anomalia: 'Detecte anomalias: picos, discrepâncias entre sensores, leituras suspeitas. Explique causas prováveis.',
    previsao: 'Com base no padrão histórico e Open-Meteo, estime como o ambiente interno se comportará nas próximas 3-6h. Melhor horário para ventilação natural.',
    diaria:   'Relatório diário: padrão de temperatura ao longo do dia, qualidade do ar, comparação entre as três fontes, inércia térmica, recomendações.',
    semanal:  'Relatório semanal: tendências, eficiência de isolamento térmico, drift entre DHT11 e DHT22, recomendações de manutenção.'
};

const prompt = ctx + '\n' + (sufixos[tipo] || 'Faça uma análise geral.');

msg._prompt = prompt;
msg._tipo   = tipo;

msg.url     = 'https://api.deepseek.com/v1/chat/completions';
msg.method  = 'POST';
msg.headers = {
    'Content-Type':  'application/json',
    'Authorization': 'Bearer sk-ee1ca89d83434633b0d62f4c4b22a5fc'
};
msg.payload = JSON.stringify({
    model:       'deepseek-chat',
    max_tokens:  600,
    temperature: 0.4,
    messages: [
        { role: 'system', content: 'Você é um especialista em conforto térmico e análise de dados climáticos. Responda em português brasileiro. Seja técnico mas acessível. Sem markdown.' },
        { role: 'user',   content: prompt }
    ]
});
return msg;

const body   = msg.payload;
const tipo   = msg._tipo;
const agora  = new Date().toISOString().replace('T',' ').substring(0,19);

if (!body || !body.choices || !body.choices[0]) {
    msg.payload = { erro: 'DeepSeek não respondeu. Tente novamente.' };
    return [msg, null];
}

const texto  = body.choices[0].message.content.trim();
const tokens = body.usage?.total_tokens || null;

// Prepara INSERT
const msgInsert = {
    topic:   'INSERT INTO analises_ia (tipo, resultado, tokens_usados, gerado_em) VALUES (?, ?, ?, NOW())',
    payload: [tipo, texto, tokens],
    _resposta: { resultado: texto, tipo, tokens_usados: tokens, gerado_em: agora }
};

return [null, msgInsert];

msg.topic   = 'SELECT tipo, resultado, tokens_usados, DATE_FORMAT(gerado_em, \'%d/%m %H:%i\') AS gerado_em FROM analises_ia ORDER BY gerado_em DESC LIMIT 5';
msg.payload = [];
return msg;

// ESP32 publica { 'online': true } em leds/status
const online = msg.payload?.online ?? false;
msg.payload  = { tipo: 'status', online };
return msg;

const acao = msg.payload?.acao;
if (acao === 'led')  return [msg, null];
if (acao === 'oled') return [null, msg];
return [null, null];

const design = msg.payload.design;
msg.topic   = 'oled/design';
msg.payload = JSON.stringify({ design });
msg.qos     = 1;
msg.retain  = true;
return msg;

const estado = msg.payload.estado;
// Payload que o ESP32 vai receber
// estado pode ser: 'verde', 'amarelo', 'vermelho', 'off'
msg.topic   = 'leds/comando';
msg.payload = JSON.stringify({ led: estado });
msg.qos     = 1;
msg.retain  = false;
return msg;

const d = msg._dados;
if (!d) return [null, null];
if (d.fonte !== 'dht22') return [null, null];

const nivelLabel = {
    conforto:        'CONFORTO',
    cautela:         'CAUTELA',
    extrema_cautela: 'CAUT.EXT.',
    perigo:          'PERIGO',
    perigo_extremo:  'PERIGO EXT'
};

const msgHiveMQ = {
    topic:   'oled/dados',
    payload: JSON.stringify({
        temperatura: d.temperatura,
        umidade:     d.umidade,
        heat_index:  d.heat_index,
        nivel:       d.nivel
    }),
    qos:    0,
    retain: true
};

const msgDash = {
    payload: {
        tipo:        'dados',
        temperatura: d.temperatura,
        umidade:     d.umidade,
        nivel_label: nivelLabel[d.nivel] || 'CONFORTO'
    }
};

return [[msgHiveMQ], [msgDash]];

const rows = msg.payload;
if (!rows || rows.length === 0) {
    node.warn('Sem dados para análise automática');
    return null;
}

// Agrupa por fonte
const fontes = {};
rows.forEach(r => {
    if (!fontes[r.fonte]) fontes[r.fonte] = [];
    fontes[r.fonte].push(r);
});

// Resumo por fonte
const agora = new Date();
const hora  = agora.getHours();
let periodo = hora >= 6 && hora < 12 ? 'manhã'
            : hora >= 12 && hora < 18 ? 'tarde'
            : hora >= 18 && hora < 24 ? 'noite'
            : 'madrugada';

let ctx = `Análise automática das últimas 6 horas (período: ${periodo}) — Catanduva, SP\n\n`;

for (const [fonte, dados] of Object.entries(fontes)) {
    const temps = dados.map(d => d.temperatura);
    const umids = dados.map(d => d.umidade);
    const his   = dados.map(d => d.heat_index);
    const tMin  = Math.min(...temps).toFixed(1);
    const tMax  = Math.max(...temps).toFixed(1);
    const tMed  = (temps.reduce((a,b)=>a+b,0)/temps.length).toFixed(1);
    const uMed  = (umids.reduce((a,b)=>a+b,0)/umids.length).toFixed(0);
    const uMin  = Math.min(...umids).toFixed(0);
    const uMax  = Math.max(...umids).toFixed(0);
    const hiMax = Math.max(...his).toFixed(1);

    // Pega primeira e última hora com valores
    const primeira = dados[0];
    const ultima   = dados[dados.length - 1];

    // Detecta tendência
    const tendencia = parseFloat(ultima.temperatura) > parseFloat(primeira.temperatura) ? 'subindo' : 'caindo';

    const local = fonte === 'dht22' ? 'interno (DHT22)' : fonte === 'dht11' ? 'externo (DHT11)' : 'Open-Meteo';
    ctx += `Sensor ${local}: temp média ${tMed}°C (min ${tMin} às ${primeira.hora}, max ${tMax}), `;
    ctx += `umidade média ${uMed}% (min ${uMin}%, max ${uMax}%), `;
    ctx += `Heat Index máx ${hiMax}°C, temperatura ${tendencia} ao longo do período.\n`;
}

ctx += `\nTotal de leituras: ${rows.length}\n`;

const prompt = ctx + `
Faça uma análise narrativa e natural em 3-4 frases sobre como foram essas últimas 6h considerando:
- Como estava a temperatura interna vs externa
- Se o ambiente estava confortável, seco ou úmido
- Qualquer tendência interessante observada
- Use linguagem natural como se estivesse descrevendo para alguém o clima do período (${periodo})
- Não use bullet points, escreva em parágrafo corrido`;

msg.url     = 'https://api.deepseek.com/v1/chat/completions';
msg.method  = 'POST';
msg.headers = {
    'Content-Type':  'application/json',
    'Authorization': 'Bearer sk-ee1ca89d83434633b0d62f4c4b22a5fc'
};
msg.payload = JSON.stringify({
    model:       'deepseek-chat',
    max_tokens:  400,
    temperature: 0.6,
    messages: [
        { role: 'system', content: 'Você é um assistente climático que descreve as condições do ambiente de forma natural e conversacional em português brasileiro. Seja conciso mas descritivo.' },
        { role: 'user', content: prompt }
    ]
});
return msg;

const body  = msg.payload;
if (!body || !body.choices || !body.choices[0]) {
    node.warn('DeepSeek não respondeu na análise automática');
    return null;
}

const texto  = body.choices[0].message.content.trim();
const tokens = body.usage?.total_tokens || null;
const agora  = new Date().toISOString().replace('T',' ').substring(0,19);

const msgInsert = {
    topic:   "INSERT INTO analises_ia (tipo, resultado, tokens_usados, gerado_em) VALUES (?, ?, ?, NOW())",
    payload: ['automatica', texto, tokens],
    _resposta: { resultado: texto, tokens_usados: tokens, gerado_em: agora }
};

return [msgInsert];

msg.topic   = "SELECT resultado, tokens_usados, "
            + "DATE_FORMAT(gerado_em, '%d/%m %H:%i') AS gerado_em "
            + "FROM analises_ia WHERE tipo = 'automatica' "
            + "ORDER BY gerado_em DESC LIMIT 4";
msg.payload = [];
return msg;

const acao = msg.payload?.acao;
if (acao === 'analisar')       return [msg, null, null];
if (acao === 'historico')      return [null, msg, null];
if (acao === 'historico_auto') return [null, null, msg];
return [null, null, null];

if (msg.payload?.acao === 'buscar') {
    msg.topic   = 'SELECT fonte, temperatura, umidade, heat_index, nivel_alerta, criado_em '
                + 'FROM leituras '
                + 'WHERE criado_em >= NOW() - INTERVAL 24 HOUR '
                + 'ORDER BY criado_em ASC';
    msg.payload = [];
    return msg;
}
return null;

msg.payload = (msg.payload || []).map(r => ({
    ...r,
    criado_em: r.criado_em instanceof Date
        ? r.criado_em.toISOString().replace('T',' ').substring(0,19)
        : r.criado_em
}));
return msg;
